// // This module decodes a 4-bit input into a 16-bit output with all outputs active except for the one corresponding to the input
module decoder4to16 (  
    input [3:0] in,  
    output reg [15:0] out  
);  
    always @(*) begin  
        out = 16'b0; // Initialize all outputs to low  
        out[in] = 1'b1; // Set the output corresponding to the input  
    end  
endmodule
